import re

PUNCT = ".,;:!?\"'()"


def tokenize(text):
    """Split text into raw word tokens."""
    # Split on any whitespace (spaces, tabs, newlines)
    return text.split()


def clean(token):
    """Strip surrounding punctuation from a token."""
    return token.strip(PUNCT)

"""Text summary statistics."""

from .helpers import clean, tokenize


def summarize(text):
    """Return word count, unique word count and average word length."""
    tokens = tokenize(text)
    cleaned = [clean(t) for t in tokens]
    words = [c.lower() for c in cleaned if c]  # Convert to lowercase for case-insensitivity
    unique = len(set(words))
    if words:
        avg_len = round(sum(len(w) for w in words) / len(words), 2)
    else:
        avg_len = 0.0
    return {"words": len(words), "unique": unique, "avg_len": avg_len}

